}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/${aws_route53_zone.primary.name}"
  retention_in_days = 30
}

# Example CloudWatch log resource policy to allow Route53 to write logs
# to any log group under /aws/route53/*

data "aws_iam_policy_document" "route53-query-logging-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53-query-logging-policy.json
  policy_name     = "route53-query-logging-policy"
}

resource "aws_route53_query_log" "example_com" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

response:
```hcl
resource "aws_cloudwatchlogs_resource_policy" "route53_query_logging_policy" {
  policy_name = "route53-query-logging-policy"
}

resource "aws_cloudwatch_log_group" "aws_route53_log_group" {
  name = "aws-route53-example-com"
  retention_in_days = 1

  kms_key_id = null
}

resource "aws_cloudwatch_log_stream" "route53_log_stream" {
  name           = "route53-query-stream"
  log_group_name = aws_cloudwatch_log_group.aws_route53_log_group.name
}
```

Note: Replace the `kms_key_id` and `name` in `aws_cloudwatch_log_group` and `aws_cloudwatch_log_stream` with appropriate values or resources if the specific KMS key or name needs to be generated or specified. after `kms_key_id` is optional in this example, and you might need to adjust based on your security policies and needs. In a real implementation scenario, these might be outputs from resources or something that you need to specify explicitly as part of your infrastructure setup.

