terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.us_east_1, aws.eu_west_1 ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

provider "aws" {
  alias  = "eu_west_1"
  region = "eu-west-1"

  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


