variable "web_app_name" {
  description = "The name of the web application"
  type        = string
  default     = "web-app"
}

variable "namespace" {
  description = "The namespace to create resources in"
  type        = string
  default     = "default"
}

variable "container_port" {
  description = "The port on which the container listens"
  type        = number
  default     = 80
}

variable "replicas" {
  description = "The number of desired instances of the web application"
  type        = number
  default     = 2
}

resource "kubernetes_namespace" "example" {
  metadata {
    name = var.namespace
  }
}

resource "kubernetes_deployment" "example" {
  metadata {
    name      = var.web_app_name
    namespace = kubernetes_namespace.example.metadata[0].name
  }

  spec {
    replicas = var.replicas

    selector {
      match_labels = {
        App = var.web_app_name
      }
    }

    template {
      metadata {
        labels = {
          App = var.web_app_name
        }
      }

      spec {
        container {
          image = "nginx:1.19.6"
          name  = var.web_app_name

          port {
            container_port = var.container_port
          }
        }
      }
    }
  }
}

resource "kubernetes_service" "example" {
  metadata {
    name      = var.web_app_name
    namespace = kubernetes_namespace.example.metadata[0].name
  }

  spec {
    selector = {
      App = kubernetes_deployment.example.spec[0].template[0].metadata[0].labels.App
    }

    port {
      node_port   = 30081
      port        = var.container_port
      target_port = var.container_port
    }

    type = "NodePort"
  }
}

