    auth    = "CODEBUILD"
    type    = "GITHUB"
    location = "https://github.com/example/repo"
  }

  artifacts {
    primary_artifacts = {
      files = ["/example/output"]
      secondary_artifacts = {
        examples = {
          files     = ["exampleArtifact1", "exampleArtifact2"]
          namespace  = "com.example"
        }
      }
    }
  }
}
