resource "aws_lex_bot" "order_pizza_bot" {
  name = "OrderPizzaBot-${random_id.suffix.hex}"
  description = "A bot to order pizza using Amazon Lex"
  locale = "en-US"
  child_workflow_execution_config {
    execution_role = aws_lex_bot_role_lex_execution_role. 
  }
  intents {
    intent {
      intent_name = "OrderPizzaIntent"
      slots {
        slot {
          name = "PizzaSize"
          slot_type = "AMAZON.NUMBER"
        }
        slot {
          name = "Toppings"
          slot_type = "AMAZON.NUMBER"
        }
      }
      confirmation_prompt {
        message = "Are you sure you want to order a pizza with ${requested_slots.Toppings}."
      }
      rejection_statement {
        message = "Sorry, I didn't understand that. Please specify the toppings you'd like on your pizza."
      }
      dialog_code_hook {
        message = "Please provide a confirmation to proceed with the pizza order."
      }
    }
  }
  confirmation_setting {
    prompt_consequence {
      message = "What topping size would you like on your pizza?"
    }
    rejections {
      message = "I didn't understand that. What size topping would you like on your pizza?"
    }
  }
  prefix = "Order a pizza " # This is a greeting to capture user engagement
  fulfillment_activity {
    type = "CodeHook"
    endpoint = aws_lex_bot_fulfillment.lex_endpoint
  }
  availability_sampling_cipher_id = aws_kms_key_lex.endpoint_id
}

