Here is the Terraform configuration for creating an AWS Lex V2 bot.

```hcl
resource "aws_lex_bot" "example" {
  bot_name = "sampleLexBot"
  description = "Sample bot to handle the V2 customer assistant experience"
}

resource "aws_lex_bot_locale" "example_locale" {
  bot_id         = aws_lex_bot.example.id
  locale         = "en-US"
  checksum      = "checksum"
}

resource "aws_lex_intent" "example_intent" {
  bot_id            = aws_lex_bot.example.id
  bot_version    = aws_lex_bot.example.version
  checksum           = "checksum"

  slots = [
    {
      name  = "slotname"
      capacity = "capacity value"
      type = "slot-type"
    },
  ]
}

resource "aws_lex_slot_type" "example_slot_type" {
  name   = "slot-name"
}

resource "aws_lex_slot_fill" "example_intent" {
  bot_id            = aws_lex_bot.example.id
  checksum           = "checksum"
  slot_to_fill      = aws_lex_slot_type.example.id
  content           = "dummy content based on constraint"
}

resource "aws_lex_bot_alias" "example_alias" {
  bot_id           = aws_lex_bot.example.id
  bot_version    = aws_lex_bot.example.version
  alias           = "alias"
  checksum       = "checksum"
  description    = "description for alias"
}

resource "aws_lex_bot_alias_history" "example_history" {
  alias = aws_lex_bot_alias.example.alias
  bot_id           = aws_lex_bot.alias.bot_id
  bot_version    = aws_lex_bot.alias.bot_version
  speech_input = "speech"
  checksum = "checksum"
}
```

This configuration creates an Amazon Lex bot with the necessary intents and slot types. For more complex setups, you might need additional configurations for slot fill statements, custom permission for AWS Lambda (if your bot uses Lambda),etc. Make sure to replace placeholders like `bot_id`, `checksum`, `slot_name`, `slot-type`, etc., with your actual configuration values where applicable.

