    bucket_arn   = aws_s3_bucket.firehose_bucket.arn
    prefix      = ""  // No prefix, as we're delivering to HTTP endpoint directly
    error_output_type = "s3" // Error output can still be written to S3
  }
}

resource "aws_kinesis_firehose_delivery_stream" "http_endpoint" {
  type                              = "DirectPut"
  uncompressed_data_enabled         = true
  monitoring_logging_options {
    s3_bucket_arn = aws_s3_bucket.monitoring.bucket_arn
    monitoring_interval = "60" // in seconds
  }
}

resource "aws_cloudwatch_log_group" "log_group" {
  name = "/aws/kinesis/firehose"
}
```

