resource "aws_kinesis_analytics_application" "analytics_app" {
  name = "basic-kinesis-analytics-${random_id.suffix.hex}"

  input {
    name = "my_log_stream_input"
    app_managed        = false
    kinesis_input {
      resource_arn = "arn:aws:kinesis:aws:region:account:stream/your_log_stream"
      role_arn      = aws_iam_role.example.  # Assume aws_iam_role with necessary policies already defined
      configuration      = "{
        "InputStartingPositionConfiguration": {"InputStartingPositionConfigurationConfiguration": {"Timestamp": "EARLIEST"}}"
    }
  }

  environment {
    type = "SQL"
    mode = "ESTIMATION"
    parameters = {
      sql                = "SELECT STREAM(*) FROM STREAMS"
    }

    // Assume again other necessary configurations for SQL, like RuntimeS3Config and SQLApplicationConfiguration are set here
    code    = """
      -- SQL statements here
      SELECT STREAM(*) FROM STREAMS
      FOR STREAM() IN STREAMS
      INSERT INTO STREAMS SELECT STREAM(*)"""
  }
}

