resource "aws_route53_health_check" "example_health_check" {
  fqdn              = "example.com"
  type              = "HTTPS"
  resource_path     = "/foobar"
  port              = 443
  region            = "us-east-1"
  failure_threshold = 3
  success_threshold = 3
  health_check_config {
    health_check_ip_protocol = "IPV4"
    failure_threshold_periods     = 3
    success_threshold_periods    = 3
  }

  failover_config {
    type                = "PRIMARY"
    resource_record_set {
      incoming                         = aws_route53_health_record.example_health_check.set_identifier != null ? aws_route53_health_record.example_health_check.id : null
    }
  }

  failover_record_set {
    secondary_resource_record_set {
      ge             = "us-east-1"
      failover_type = "PRIMARY"
      incoming      = aws_route53_health_record.example_health_check.set_identifier != null ? aws_route53_health_record.example_health_check.id : null
    }
  }
  hosted_zone_id                 = data.aws_route53_zone.example.id
}

