  image_tag                = data.aws_ecr_public.latest.images[0].image_tag
  aws_tags               = data.aws_caller_identity.current_identity_tags
  workspace_name          = "terraform-workspace-name"
}

module "eks" {
  source                            = "terraform-aws-modules/eks/aws"
  cluster_name                      = "my-eks-cluster"
  cluster_version                  = "1.21"
  cluster_addons                  = {
    kube_stalk = {
      addon_version = "stable",
      cluster_role_external_services = []
    }
  }
  subnets = ["subnet-12345678", "subnet-87654321"]
  vpc_id            = "vpc-1234abcd"
  node_groups = [
    {
      instance_types = ["m5.large"]
      ami_type        = "AL2_x86_64"
      capacity_type  = "ON_DEMAND"
    },
  ]
  cluster_authenticate = true
  node_public_key     = true
}

data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_id
}

data "aws_eks_cluster_auth" "cluster_auth" {
  cluster_name = module.eks.cluster_id
}

provider "helm" {
  alias  = "eks"
  alias  = data.aws_eks_cluster.cluster.endpoint
  kubeconfig   = data.aws_eks_cluster_auth.cluster.kubeconfig
}
provider "kubernetes" {
  alias  = "eks"
  alias  = data.aws_eks_cluster.cluster.endpoint
  kubeconfig   = data.aws_eks_cluster_auth.cluster.kubeconfig
