resource "null_resource" "patch_core_dns" {
  triggers = {
    "always" = ""
  }

  provisioner "local-exec" {
    command = "kubectl patch -n kube-system deployment/coredns"
    environment = {
      "KUBE_API_URL" = "https://${aws_eks_cluster.your_cluster.endpoint}"
