Here's the Terraform configuration in HCL format to create an AWS IAM role for an Amazon EKS cluster, and then define the EKS cluster with the specified subnets for the VPC configuration:

```hcl
resource "aws_iam_role" "demo" {
  name = "eks-cluster-demo"

  assume_role_policy {
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Effect = "Allow"
          Principal = {
            Service = "eks.amazonaws.com"
          }
          Action = "sts:AssumeRole"
        },
      ]
    })
}

resource "aws_iam_policy_attachment" "AmazonEKS" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo.name
}

resource "aws_eks_cluster" "demo" {
  name                = "demo"
  role_arn           = aws_iam_role.demo.arian

  vpc_config {
    subnet_ids = ["subnet-0bb1c79de3EXAMPLE", "subnet-06430e40EXAMPLE"] // Replace with actual subnet IDs

    endpoint_private_access = false
    endpoint_public_access  = false
  }

  depends_on = [aws_iam_policy_attachment.AmazonEKS]
}
```

To ensure proper execution, replace `subnet-0bb1c79de3EXAMPLE` and `subnet-06430e40EXAMPLE` with actual subnet IDs in the `us-east-1` region. Furthermore, modify any placeholder ARN values to fit your actual environment configurations.

