response:
To create an AWS S3 bucket with versioning enabled and specify an expected bucket owner, you can use the following Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "sample" {
  bucket = "sample"
  versioning {
    enabled = true
  }
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid = "ExpectedBucketOwner",
        Effect = "Allow",
        Principal = {
          AWS = "arn:aws:iam::123456789012:root"
        },
        Action = "s3:*",
        Resource = "${aws_s3_bucket.sample.arn}/*"
      },
    ]
  })
}

resource "aws_s3_bucket" "replicate" {
  bucket = aws_s3_bucket.sample.bucket
  versioning {
    enabled = true
  }
}
```

This configuration creates an S3 bucket with versioning enabled and sets an ownership policy to ensure the bucket owner is consistent with the specified AWS account. If further bucket replication or region-specific setup is needed, you would configure that in the `aws_s3_bucket` resource block accordingly.

