response:
Certainly! Below is the Terraform configuration for creating an AWS S3 bucket with a unique name, an ACL for the bucket, and a bucket policy that allows `s3:GetObject` actions with a condition based on the AWS Referer header.

```hcl
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "random_string" "bucket_name" {
  length  = 8
}

resource "aws_s3_bucket" "unique_bucket" {
  bucket = "my_unique_bucket_${random_id.bucket_suffix.hex}"
}

resource "aws_s3_bucket acl" "unique_bucket_acl" {
  bucket = aws_s3_bucket.unique_bucket.id
  rule {
    bucket = aws_s3_bucket.unique_bucket.id
    sid    = aws_s3_bucket.unique_bucket.id
    type   = "GROUP"
    permissions = "READ"
  }
}

resource "aws_s3_bucket_policy" "unique_bucket_policy" {
  bucket = aws_s3_bucket.unique_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "Allow "all" access from "all" Referers"
        Effect    = "Allow"
        Principal = "*"
        Action   = "s3:GetObject"
        Resource = [
          "${aws_s3_bucket.unique_bucket. arn}/*"
        ]
        Condition {
          Variable = "aws:Referer"
          Values   = ["*"]
        }
      }
    ]
  })
}
```

In this configuration:
- The `aws_s3_bucket` resource uses `random_id` to create a unique bucket name.
- The ACL grants `READ` permissions to all principals for the bucket.
- The bucket policy includes a condition allowing `s3:GetObject` from all Referers, denoted by `"aws:Referer"` and `"*"` in the policy document.

