Here's a Terraform configuration setup for AWS S3 buckets with specific access control and logging features:

```hcl
resource "random_id" "s3_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket" "private_bucket" {
  bucket = "my-private-bucket-${random_id.s3_suffix.hex}"
  acl    = "private"
  versioning {
    enabled = true
  }
}

resource "aws_s3_bucket_acl" "private_bucket_acl" {
  bucket = aws_s3_bucket.private_bucket.id
  grants = [
    {
      permission = "READ"
      type      = "Group"
      uri       = "http://acs.amazonaws.com/groups/s3/LogDelivery"
    },
    {
      permission = "FULL_CONTROL"
      type      = "CanonicalUser"
      uri       = "http://www.mycompany.com/CanonicalUser"
    },
  ]
}

resource "aws_s3_bucket" "logging_bucket" {
  bucket = "my-logging-bucket-${random_id.s3_suffix.hex}"
  acl    = "log-delivery-write"
  versioning {
    enabled = true
  }
  logging {
    target_prefix = "log/"
    target_bucket  = aws_s3_bucket.private_bucket.id
  }
}
```

This configuration defines two S3 buckets with distinct names generated using the `random_id` resource. The first bucket, `private_bucket`, is set to private with versioning enabled, and the second bucket, `logging_bucket`, uses the AWS predefined ACL to allow log delivery writes, logging to the `private_bucket` with specific file prefixes.

