Here is the Terraform configuration for the requested AWS infrastructure in HCL format:

```hcl
provider "aws" {
  region = "us-west-3"
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_subnet" {
  vpc_id = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-3a"
}

resource "aws_subnet" "private_subnet1" {
  vpc_id = aws_vpc.example.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-3b"
}

resource "aws_subnet" "private_subnet2" {
  vpc_id = aws_vpc.example.id
  cidr_block = "10.0.3.0/24"
  availability_zone = "us-west-3c"
}

resource "aws_instance" "web_server" {
  ami           = "ami-0c55b159cbfafe1f0" # Example AMI ID for web server
  instance_type = "t2.micro"              # Choose a suitable EC2 type
  subnet_id     = aws_subnet.public_subnet.id
}

resource "aws_instance" "application_server" {
  ami           = "ami-05d72847ff82f9288" # Example AMI ID for application server
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.private_subnet1.id
}

resource "aws_db_instance" "db" {
  allocated_storage = 20
  db_instance_class = "db.t3.micro"
  engine            = "mysql"           # Example engine type for RDS
  db_subnet_group_name = length(db_subnet_group.) # Assuming a DB subnet group is defined elsewhere
  skip_final_snapshot = true
  subnet_id          = aws_subnet.private_subnet2.id
