response:
To trigger an `aws_lambda_function` called `test_lambda` whenever an EC2 image is created, you can use Amazon EventBridge and a Lambda function to respond to state changes in the EC2 service. Here is the Terraform configuration to achieve that:

```hcl
resource "aws_lambda_function" "test_lambda" {
  function_name = "ExampleFunction"
  handler       = "index.handler"
  role          = aws_iam_role.lambda_exec.  arn
  runtime       = "python3.8"
  // Other necessary configuration for your Lambda function.
}

resource "aws_event_bridge" "rule" {
  event_pattern = jsonencode({
    source = ["aws.ec2"],
    detail-type = ["EC2 Instance State-change Notification"]
  })

  target_id   = aws_lambda_function.test_lambda.function_name
  target_type = "AWS::Lambda::Function"

  target_input  = "{ "key", "newInstanceCreated" }"
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = "service"
        Effect = "Allow"
        Sid = ""
        Service = "lambda.amazonaws.com"
      },
    ]
  })
  managed_policy_arns = [
    "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecution",
  ]
}
```

This configuration sets up an `aws_lambda_function` and an AWS EventBridge rule to trigger the lambda function upon EC2 instance state changes from creation events. Adjust the event pattern and the target input to match the specific conditions or structure required by your lambda function.

