  alarm_name          = "example-composite-alarm"
  alarm_description   = "This alarm triggers on composite conditions."
  actions_enabled     = true

  alarm_actions = ["arn:aws:automated/AWS_Action_for_an_alarm"]

  ok_actions = ["arn:aws:automated/AWS_Action_for_ok_condition"]

  insufficient_data_actions = ["arn:aws:automated/AWS_Action_for_insufficient_data_condition"]

  alarm_rule {
