response:
To create a DynamoDB table with replicas in multiple regions as specified in the request, you can use the AWS provider's `aws_dynamodb_table` resource block to create the table and manage its attributes, including the Global Tables configuration for replication across different regions. Here's the Terraform configuration for this request:

```hcl
provider "aws" {
  region = "us-east-1"
  alias  = "primary"
}

provider "aws" {
  region = "us-west-1"
  alias  = "replica_1"
}

provider "aws" {
  region = "us-west-2"
  alias  = "replica_2"
}

resource "aws_dynamodb_table" "primary" {
  provider = aws.primary

  name         = "example-table"
  hash_key     = "id"
  billing_mode = "PAY_PER_REQUEST"

  read_capacity  = 5
  write_capacity = 5

  replica {
    region_name = aws.replica_1.region
  }

  replica {
    region_name = aws.replica_2.region
  }

  stream_specification {
    stream_enabled = true
    stream_view_type = "NEW_AND_OLD_IMAGES"
  }
}

resource "aws_dynamodb_table" "replica_1" {
  provider = aws.replica_1

  replica_of  = aws_dynamodb_table.primary.id
}

resource "aws_dynamodb_table" "replica_2" {
  provider = aws.replica_2

  replica_of = aws_dynamodb_table.primary.id
}
```

This code block creates a DynamoDB table in the `us-east-1` region and sets up global tables with replicas in `us-west-1` and `us-west-2`. Note that you primarily configure the table once and reference it within other resource blocks for regional replication.

