  region = "us-east-2"
}

resource "aws_msk_cluster" "example_cluster" {
  cluster_arn = "fs-${random_id.cluster_arn_suffix.hex}"
  broker_node_group_info {
    az_id        = "default"
    security_groups = ["${aws_security_group.example.id}"]
    client_access = "TLS"
  }
  number_of broker_nodes = 0
  serverless_cluster_enabled = true
  storage_mode = "Serverless"
}
```

This setup:
- Uses AWS as the provider in the `us-east-2` region.
- Uses a `random_id` resource to generate a suffix for the cluster ARN.
- Specifies the serverless cluster attributes, including security and access details.

