provider "aws" {
  region = "us-west-2"
}

resource "random_id" "broker_id" {
  byte_length = 2
}

resource "aws_kms_key" "msk" {
  description = "KMS key for MSK encryption"
}

resource "aws_cloudwatch_log_group" "msk" {
  name = "msk-cluster-logs"
  retention_in_days = 7
}

resource "aws_s3_bucket" "firehose" {
  bucket = "firehose-bucket-${random_id.broker_id.hex}"
  acl    = "private"
}

resource "aws_kinesis_firehose_delivery_stream" "firehose" {
  name        = "firehose-stream-${random_id.broker_id.hex}"
  destination = "extended_s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose.arn
    bucket_arn = aws_s3_bucket.firehose.arn
  }

  cloudwatch_logging_options {
    enabled = true
    log_group_arn = aws_cloudwatch_log_group.msk.arn
    log_stream_name = "firehose-logs"
  }
}

resource "aws_iam_role" "firehose" {
  name = "firehose-role-${random_id.broker_id.hex}"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "firehose.amazonaws.com"
      },
      "Action": "sts:AssumeRole"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy" "firehose" {
  role   = aws_iam_role.firehose.name
  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:ListBucketMultipartUploads",
        "s3:PutObject"
      ],
      "Resource": [
        "${aws_s3_bucket.firehose.arn}",
        "${aws_s3_bucket.firehose.arn}/*"
      ]
    },
    {
      "Effect": "Allow",
      "Action": "logs:PutLogEvents",
      "Resource": "${aws_cloudwatch_log_group.msk.arn}:*"
    }
  ]
}
EOF
}

resource "aws_msk_cluster" "example" {
  cluster_name       = "example-mnk-ca-${random_id.broker_id.hex}"
  kafka_version      = "2.4.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    ebs_volume_size = 1000
    subnet_ids      = ["subnet-12345"]
    security_group_ids = ["sg-12345"]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk.arn
  }

  open_monitoring {
    prometheus_metrics_enabled = true
  }
}

resource "aws_msk_connect_custom_plugin" "debezium" {
  plugin_name    = "debezium-sqlserver-connector-1.5.0"
  plugin_location = "s3://${aws_s3_bucket.firehose.bucket}/debezium.zip"
  kms_key_id     = aws_kms_key.msk.arn
}

resource "aws_msk_connect_connector" "example" {
  name            = "Debezium-Connector"
  cluster_arn     = aws_msk_cluster.example.arn
  kafka_broker    = aws_msk_cluster.example.bootstrap_brokers_string
  connector_class = "io.debezium.connector.sqlserver.SqlServerConnector"
  custom_plugins  = [aws_msk_connect_custom_plugin.debezium.plugin_name]

  configuration = {
    database.server.name                  = "localhost:1433"
    database.user                         = "sa"
    database.password                     = "Test1234!"
    table.include.list                    = "schema.tablename"
    snapshot.mode                         = "schema_only"
    database.history.kafka.bootstrap.servers = aws_msk_cluster.example.bootstrap_brokers_string
  }
}
