    day        = 2
    time      = "04:00-09:00" // two AoE
    // Other parameters can be left at default values if not changing
  }

  db_port = 3306
  apply_immediately = true
}

resource "aws_db_subnet_group" "example" {
  name = "example-subnet-group"
  subnet_ids         = [aws_subnet.example_az1.id, aws_subnet.example_az2.id, aws_subnet.example_az3.id]
}

resource "aws_subnet" "example_az" {
  count = 3 // For us-east-1a, us-east-1b, us-east-1c
