Certainly! Below is the Terraform configuration to create an AWS VPC with one subnet and launch an EC2 instance using a specific AMI for Ubuntu 20.04 on AMD64:

```hcl
provider "aws" {
  region = "us-west-2"
}

data "aws_ami" "ubuntu" {
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu*-jammy-20.04*"]
  }
  filter {
    name   = "architecture"
    values = ["x86_64"]
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_instance" "example" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "UbuntuInstance"
  }
}
```

This configuration sets up the AWS provider, uses AMI data source to find the latest Ubuntu 20.04 AMI, creates a VPC and a subnet inside it, and finally launches an EC2 instance using the selected AMI into the specified subnet.

