Here's the Terraform configuration for creating two AWS Chime Voice Connectors with encryption and a voice connector group:

```hcl
resource "aws_chime_voice_connector" "connector1" {
  alias       = "ChimeConnector1"
  e164_digits = "1234567890"
  requires_encryption = true
  encryption_type = "TLS"
}

resource "aws_chime_voice_connector" "connector2" {
  alias       = "ChimeConnector2"
  e164_digits = "0987654321"
  requires_encryption = true
  encryption_type = "SRTP"
}

resource "aws_chime_voice_connector_group" "group" {
  voice_connector_ids = [aws_chime_voice_connector.connector1.id, aws_chime_voice_connector.connector2.id]
}
```

This code block sets up two AWS Chime Voice Connectors, both requiring encryption, and then groups them together. Make sure to replace the `e164_digits` values with valid E.164 digits for your specific use case.

