  logging_status     = "ENABLED"
  log_types {
    log_type = "CONTENT"
    settings {
      trim_minutes = 5
    }
  }
  log_types {
    log_type = "PARTICIPANT"
    settings {
      trim_minutes = 5
    }
  }
  notification_configuration {
