  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = 48
}

resource "aws_chime_voice_connector_media_authentication_s3_location" "example" {
  voice_connector_id = aws_chime_voice_connector.example.id
  uri                = "s3://YourS3BucketName"
}

resource "aws_chime_voice_connector_media_stream" "example" {
  voice_connector_id                   = aws_chime_voice_connector.example.id
  target_application_id                = "undefined" // Replace with appropriate ApplicationId if connecting to a Chime SDK application
  destination_application_instance_id  = "undefined" // Replace with appropriate ApplicationInstanceID if connecting to a Chime SDK application

  encryption = {
