```hcl
resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

resource "aws_s3_bucket" "mybucket_analytics" {
  bucket = "mybucket.analytics"
}

resource "aws_s3_bucket" "mybucket" {
  bucket                          = "mybucket"
  acl                            = "private"

  lifecycle {
    ignore_changes = [acl, versioning]
  }

  versioning {
    enabled = false
  }
}

resource "aws_s3_bucket_analytics_configuration" "example" {
  bucket_id = aws_s3_bucket.mybucket.id

  rule {
    id              = "ExampleRule"
    filter {
      prefix = "analytics/"
    }
    destination {
      bucket_id = aws_s3_bucket.mybucket_analytics.bucket
    }
  }
  destination {
    bucket_analytics_configurations {
      enabled = true
    }
  }
}
```

This configuration creates an S3 bucket named `mybucket` and a secondary bucket for analytics results, specified by references `mybucket` and `mybucket_analytics`. The analytics configuration exports results prefixed with "analytics/" to the `mybucket_analytics` bucket.

