```hcl
resource "aws_s3_bucket" "my_bucket" {
  bucket = "mybucket"

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_s3_bucket_inventory" "my_bucket_inventory" {
  bucket      = aws_s3_bucket.my_bucket.id
  included_object_versions = "all"
  schedule {
    frequency = "Daily"
  }
  destination {
    bucket {
      format                = "XML"
      bucket_arn           = aws_s3_bucket.my_bucket.id
      account_id           = aws_s3_bucket.my_bucket.owner_id
    }
  }
}
```

This configuration creates an S3 bucket named "mybucket" and sets up a daily inventory configuration for tracking the objects in the bucket. ensures inventory reporting is turned on and the destination is decided to where the inventory reports will be stored.

