```hcl
resource "random_id" "first_bucket_suffix" {
  byte_length = 8
}

resource "random_id" "second_bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket" "first_bucket" {
  bucket = "example-logs-${random_id.first_bucket_suffix.hex}"
  acl    = "private"
}

resource "aws_s3_bucket" "second_bucket" {
  bucket = "example-backup-${random_id.second_bucket_suffix.hex}"
  acl    = "private"
}

resource "aws_s3_bucket_logging" "logging" {
  bucket = aws_s3_bucket.first_bucket.id

  target {
    bucket = aws_s3_bucket.second_bucket.id
    prefix = "log/"
  }
}
```

This configuration includes two S3 buckets with randomly generated names and a logging resource configuration that directs logs from the first bucket to the second bucket with a prefixed key of "log/".

