response:
Here's the Terraform configuration for creating an S3 bucket along with a configuration to store server access logs into a second S3 bucket:

```hcl
resource "aws_s3_bucket" "logs" {
  bucket = "my-logs-bucket-${random_pet.keepers[0]}"
  acl    = "private"
}

resource "aws_s3_bucket" "bucket" {
  bucket = "my-web-bucket-${random_pet.name}"

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default = true
      sse_kms_key_id = "your-kms-key-id"
    }
  }

  lifecycle {
    prevent_destroy = true
  }

  lifecycle_rule {
    id     = "expire-old-logs"
    enabled = true

    expiration {
      days = 90
    }

    filter {
      prefix = "/AWSLogs/"
    }
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default = true
      sse_kms_key_id = aws_kms_key.s3_key. arn
    }
  }

  logging {
    target_bucket = aws_s3_bucket.logs.id
    target_prefix   = "logs/"
  }

  versioning {
    enabled = true
  }
}

resource "random_pet" "name" {}

resource "aws_kms_key" "s3_key" {
  description             = "KMS Key for S3 bucket encryption"
  enable_key_rotation     = true
}
```

### Explanation:

- **`aws_s3_bucket` resources**: 
  - One bucket (`logs`) for storing logs.
  - Another bucket (`bucket`) with server-side encryption and logging enabled.

- **`random_pet` resource**: Generates a random name for the buckets to avoid naming conflicts.

- **`aws_kms_key` resource**: Creates an encryption key for encrypting objects stored in the S3 bucket.

The logging configuration specifies `logs` bucket as the target for storing logs, with a prefix to organize the log files, and server-side encryption is enabled to encrypt the logging data.

