    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/yourusername/your-repo.git"
    }
    environment_variable {
      name  = "BRANCH_NAME"
      value = "main"
    }
    environment_variable {
      name  = "RESULT_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/yourusername/your-repo"
    git_clone_depth = 1
  }
}

