terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "autograder_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_internet_gateway" "autograder_gw" {
  vpc_id = aws_vpc.autograder_vpc.id
}

resource "aws_route_table" "autograder_route_table" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.autograder_gw.id
  }
}

resource "aws_route_table_association" "autograder_association" {
  subnet_id      = aws_subnet.autograder_subnet.id
  route_table_id = aws_route_table.autograder_route_table.id
}

resource "aws_security_group" "autograder_sg" {
  vpc_id = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_codebuild_project" "autograder_build" {
  name          = "cs-class-autograder"
  service_role  = aws_iam_role.codebuild.arn
  build_timeout = "5"

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:4.0"
    type                        = "LINUX_CONTAINER"
    privileged_mode             = false
    environment_variable {
      name  = "GITHUB_REPO"
      value = "your-github-repo"
    }
    environment_variable {
      name  = "GITHUB_BRANCH"
      value = "main"
    }
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-github-repo.git"
    git_clone_depth = 1
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "NO_CACHE"
  }
}

resource "aws_iam_role" "codebuild" {
  name = "codebuild-autograder-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  role       = aws_iam_role.codebuild.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

resource "aws_s3_bucket" "autograder_results" {
  bucket = "cs-class-autograder-results"
  acl    = "private"

  versioning {
    enabled = true
  }

}

resource "aws_iam_role_policy" "codebuild_results_policy" {
  name   = "codebuild-results-policy"
  role   = aws_iam_role.codebuild.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
    ]
  })
}

