  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example_subnet" {
  vpc_id            = aws_vpc.example_vpc.id
  cidr_block         = "10.0.0.0/24"
  availability_zone  = "us-west-2"
}

resource "aws_security_group" "example_sg" {
  vpc_id = aws_vpc.example_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }
}

resource "aws_codebuild_project" "example_project" {
  name     = "example-codebuild-project"
  artifacts {
    type = "S3"
    location = "s3://${aws_s3_bucket.code_build_output.id}/"
  }
  environment {
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "alpine"
    type         = "LINUX_CONTAINER"
  }
  source {
    type      = "GITHUB"
    git_clone_depth = 1
    location = "https://github.com/source-location"
  }
  vpc_config {
    vpc_id            = aws_vpc.example_vpc.id
    security_group_id = aws_security_group.example_sg.id
  }
}
```

This configuration sets up the AWS S3 bucket, VPC, subnet, and security group as requested, along with an AWS CodeBuild project configured to use the specified S3 bucket for artifacts. The security group is configured to restrict access to allow no ingress or egress, effectively blocking internet access.

