  path_part    = "cats"
}

resource "aws_api_gateway_method" "uploadCatImageMethod" {
  rest_api_id   = aws_api_gateway_rest_api.CatImageAPI.id
  resource_id    = aws_api_gateway_resource.CatImageResource.id
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "uploadCatImageIntegration" {
  rest_api_id = aws_api_gateway_rest_api.CatImageAPI.id
  resource_id  = aws_api_gateway_method.uploadCatImageMethod.resource_id
  http_method  = aws_api_gateway_method.uploadCatImageMethod.http_method

  type        = "MOCK"
  request_templates = {
    "application/json" = "{}"
  }
}

resource "aws_api_gateway_integration" "viewCatImageIntegration" {
  rest_api_id   = aws_api_gateway_rest_api.CatImageAPI.id
  resource_id    = aws_api_gateway_method.viewCatImageMethod.resource_id
  http_method   = "GET"

  integration_type = "AWS"
  integration_method = "POST"
  integration_uri = "arn:aws:apigateway:${var.aws_region}:s3:path/${aws_s3_bucket.cat_photos.id}/cats/*"

  credentials   = "arn:aws:iam::${var.aws_account_id}:role/APIGatewayS3FullAccess"
}

resource "aws_s3_bucket_policy" "catBucketPolicy" {
  bucket = aws_s3_bucket.cat_photos.id

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action    = ["s3:PutObject", "s3:GetObject"],
        Effect    = "Allow",
        Resource  = "arn:aws:s3:::${aws_s3_bucket.cat_photos.id}/cats/*",
        Principal = { AWS = aws_api_gateway_integration.viewCatImageIntegration.credentials },
      },
    ],
  })
}

resource "aws_api_gateway_method_response" "catsUploadResponse" {
  rest_api_id   = aws_api_gateway_rest_api.CatImageAPI.id
  resource_id    = aws_api_gateway_resource.CatImageResource.id
  http_method   = aws_api_gateway_method.uploadCatImageMethod.http_method
  status_code   = "200"
  response_models = jsonencode({ "application/json": "" })
}

resource "aws_api_gateway_method_integration" "catsUploadIntegration" {
  rest_api_id              = aws_api_gateway_rest_api.CatImageAPI.id
  resource_id              = aws_api_gateway_method.uploadCatImageMethod.resource_id
  http_method              = aws_api_gateway_method.uploadCatImageMethod.http_method

  integration_uri          = aws_api_gateway_integration.uploadCatImageIntegration.integration_uri
  integration_http_method = "POST"
  passthrough_behavior    = "WHEN_NO_TEMPLATES"
}
```

This configuration sets up S3 to store cat images and an API Gateway with a mock integration that allows users to upload cat images. It also defines a method response as well as integration response and method settings to enable proper interaction with S3. Lastly, it grants appropriate permission to an AWS IAM role using the S3 bucket policy that is necessary for API Gateway permissions to access cat images in S3.

