To address the request, we need to provision an EC2 instance and configure AWS Backup to back it up every day at midnight. The following Terraform configuration demonstrates how this can be accomplished using AWS EC2 and AWS Backup services. It assumes that necessary VPC and subnet configurations are already set up. Here's a possible configuration:

```hcl
resource "aws_instance" "backup_ec2" {
  ami           = "ami-0c55b159cbfafe1f0"  # Example AMI ID for Ubuntu
  instance_type = "t2.micro"  # Example instance type
  subnet_id     = "subnet-12345abc" # Example subnet ID in your VPC

  user_data = <<USERDATA-cloud-init
    #cloud-config
    timezone: America/Los_Angeles
    backup:
      type: S3
      triggers: [{"name": "daily-backup", "cron": "0 0 * * * *"}]
  <<USERDATA>>
}

data "aws_ami" "latest" {
  most_recent = true

  filter {
    name   = "name"
    values = ["ubuntu-server"]
  }

  owners = ["099720109477"]
}

resource "aws_backup_vault" "saving_vault" {
  name = "terraform-backup-vault"
}

resource "aws_backup_plan" "nightly_backup_plan" {
  name = "nightly-backup-plan"

  rule {
    rule_name         = "nightly-backup"
    target_vault_name = aws_backup_vault.saving_vault.name
    schedule = {
      start_window = {
        hour      = 22
        minute   = 0
        timezone = "EASTERN"
      }

      lifecycle = {
        delete_after = 30 // Retention of 30 days
      }

      schedule_expression = "cron(0 0 * * ? *)" // Daily backup at midnight
    }
  }
}

resource "aws_backup_selection" "backup_selection" {
  rule_id = aws_backup_plan.nightly_backup_plan.rule_ids[0]
  resources = [aws_backup_vault.saving_vault.name]

  selection {
    resource_type = "AWS::EC2::Volume"
    resource_id   = "/aws/volumes/${aws_instance.backup_ec2.id}"
  }
}
```

### Explanation:
- **AWS EC2 instance:** We define an AWS instance using a specified AMI and instance type. The backup schedule is incorporated using `user_data` with cloud-init commands.
- **AWS Backup Vault:** A vault is created and named `terraform-backup-vault`.
- **AWS Backup Plan:** This backup plan is named `nightly-backup-plan` and sets a night time backup schedule for the EC2 instance.
- **AWS Backup Selection:** This specifies that the backup plan should target volumes of EC2 instances.

Note: Replace placeholders like `ami-0c55b159cbfafe1f0` and `subnet-12345abc` with actual IDs in your AWS configurations.

