provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "video_streaming_bucket" {
  bucket = "video-streaming-content"
  acl    = "private"

  versioning {
    enabled = true
  }

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_cloudfront_distribution" "video_streaming_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_streaming_bucket.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_streaming_bucket.id}"

    s3_origin_config {
      origin_access_identity = "origin-access-identity/cloudfront/${aws_cloudfront_origin_access_identity.video_streaming_identity.id}"
    }
  }

  enabled = true
  default_cache_behavior {
    target_origin_id       = aws_s3_bucket.video_streaming_bucket.origin_id
    viewer_protocol_policy = "allow-all"
    trusted_signers       = ["self"]
    compress             = true
    lambda_function_association {
      event_type   = "viewer-request"
      lambda_arn   = "arn:aws:lambda:us-west-2:1234567890:func:exampleFunction"
      include_body = false
    }
  }

  price_class = "PriceClass_100"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations      = ["NA", "EU", "SA"]
    }
  }

  viewer_certificate {
    cloudfront_id = aws_cloudfront_ssl_certificate.example.id
  }
}

resource "aws_cloudfront_origin_access_identity" "video_streaming_identity" {
  comment = "S3 Video Streaming Access Identity"
}

resource "aws_cloudfront_ssl_certificate" "example" {
  certificate_arn = "arn:aws:acm:us-west-2:1234567890:certificate/abcd1234"
}

resource "aws_route53_record" "video_streaming_zone" {
  zone_id   = aws_route53_zone.example.zone_id
  name      = "streaming.example.com"
  type      = "A"
  alias     = true
  alias_zone_id = aws_route53_zone.example.zone_id
  alias_dns_name = aws_cloudfront_distribution.video_streaming_distribution.domain_name

  ttl = "60"
}

