      lambda_arn   = "arn:aws:lambda:us-west-2:1234567890:func:exampleFunction"
      include_body = false
    }
  }

  price_class = "PriceClass_100"

  restrictions {
    geo_restriction {
      restriction_type = "whitelist"
      locations      = ["NA", "EU", "SA"]
    }
  }

  viewer_certificate {
    cloudfront_id = aws_cloudfront_ssl_certificate.example.id
  }
}

resource "aws_cloudfront_origin_access_identity" "video_streaming_identity" {
  comment = "S3 Video Streaming Access Identity"
}

resource "aws_cloudfront_ssl_certificate" "example" {
  certificate_arn = "arn:aws:acm:us-west-2:1234567890:certificate/abcd1234"
}

resource "aws_route53_record" "video_streaming_zone" {
  zone_id   = aws_route53_zone.example.zone_id
  name      = "streaming.example.com"
  type      = "A"
  alias     = true
  alias_zone_id = aws_route53_zone.example.zone_id
  alias_dns_name = aws_cloudfront_distribution.video_streaming_distribution.domain_name

  ttl = "60"
}
```

