Here's a Terraform configuration to create a load-balanced video streaming site infrastructure using AWS resources in HCL format:

```hcl
resource "aws_lb" "video_streaming_lb" {
  name     = "video-streaming-lb"
  arn      = "${aws_lb.video_streaming_lb.arn}"
}

resource "aws_lb_target_group" "streaming" {
  name     = "video-streaming-target-group"
  port     = 80
  protocol = "HTTP"

  vpc_id = aws_vpc.example.id
}

resource "aws_route53_zone" "video_streaming" {
  name = "video-streaming.example.com"
}

resource "aws_route53_record" "streaming_dns" {
  zone_id = aws_route53_zone.video_streaming.zone_id
  name    = "streaming.video-streaming.example.com"
  type    = "A"
  ttl     = "300"
  records = ["${aws_lb.video_streaming_lb.dns_name}"]
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_vpc_subnet" "example_subnet" {
  vpc_id      = aws_vpc.example.id
  cidr_block    = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_security_group" "example_sg" {
  name   = "video-streaming-sg"
  vpc_id = aws_vpc.example.id
}

resource "aws_security_group_rule" "allow_http" {
  type              = "ingress"
  from_port         = 80
  to_port           = 80
  protocol          = "tcp"
  cidr_blocks      = ["10.0.0.0/16"]
}

resource "aws_security_group_rule" "allow_https" {
  type              = "ingress"
  from_port         = 443
  to_port           = 443
  protocol          = "tcp"
  cidr_blocks      = ["10.0.0.0/16"]
}

resource "aws_instance" "streaming_server" {
  ami           = "ami-0c55b159cbfafe1fe"
  instance_type = "t2.micro"

  subnet_id     = aws_vpc_subnet.example_subnet.id
  security_groups = [aws_security_group.example_sg.id]
}
```

Note: Make sure to replace placeholders like `aws_vpc.example.id` and `aws_lb.video_streaming_lb.dns_name` with proper references to your actual resources. Ensure the AVI profiles for your EC2 instances match the video streaming requirements you're planning to use.

