  vpc_id                = aws_vpc.example.id
  cidr_block        = cidr(element(var.availability_zones, count.index))
  map_public_ip_on_launch = true
  availability_zone = element(var.availability_zones, count.index)

  tags = {
    Name = "example-public-subnet-${count.index}"
  }
}

resource "aws_security_group" "example_db_access" {
  vpc_id = aws_vpc.example.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port = 22
    to_port   = 22
    protocol  = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port       = 80 // HTTP
    to_port         = 80 // HTTP
    protocol       = "tcp"
    cidr_blocks    = ["0.0.0.0/0"]
  }

  tags = {
    Name = "example-db-access-security-group"
  }
}

resource "aws_db_instance" "example" {
  identifier          = "example-${random_id.db_security_group.result}"
  allocated_storage   = 5
  engine              = "mysql"
  engine_version      = "8.4.3"
  publicly_accessible = true
  vpc_security_groups = [aws_security_group.example_db_access.id]

  tags = {
    Name = "example-DB-instance"
  }
}

resource "aws_security_group" "example_subnets" {
  vpc_id = aws_vpc.example.id

  tags = {
    Name = "example-subnets-security-group"
  }
}

resource "aws_security_group" "example_subnets" {
  vpc_id     = aws_vpc.example.id
  ingress     = [aws_security_group.example_db_access]

  tags = {
    Name = "example-subnets-security-group-${aws_db_instance.example.identifier}-${random_id.db_security_group.result}"
  }
}
```

