```hcl
provider "aws" {
  region = "us-west-2" // specify your desired region
}

resource "aws_kms_key" "my_pgsql_key" {
  description = "KMS key for PostgreSQL encryption"
}

resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16" // specify the VPC CIDR block
}

resource "aws_db_subnet_group" "example" {
  name   = "my-db-subnet-group"
  subnet_ids = [aws_subnet.example.id]
}

resource "aws_rds_parameter_group" "example_pg" {
  name        = "my-parameter-group"
  family      = "11.5"
  description = "Custom Parameter Group for PostgreSQL 15"

  parameter {
    name        = "pg_version"
    value       = "15.4"
  }

  parameter {
    name        = "max_connections"
    value       = "100"
  }

  parameter {
    name        = "require_ssl"
    value       = "true"
  }
}

resource "aws_rds_cluster_parameter_group" "example_pg" {
  parameter_group_name = aws_rds_parameter_group.example_pgg.name
}

resource "aws_rds_instance" "example_db" {
  instance_class         = "db.r5.large"
  storage_type          = "gp2"
  storage_encrypted     = true
  allocated_storage     = 50
  db_instance_class    = "db.m5.large"
  engine               = "postgres"
  engine_version       = "15.4"
  multi_az             = true
  db_subnet_group_name = aws_db_subnet_group.example.name
  vpc_security_group_ids = [aws_security_group.example.id]
  backup_retention_period = 14
  skip_final_snapshot   = true

  name                  = "my-postgresql-instance"
  dbname               = "mysecuredb"
  username             = "foo"
  port                 = "5432"
  parameter_group_name = aws_rds_parameter_group.example_pg.name
  storage_encrypted    = true
  kms_key_id          = aws_kms_key.sqlite_encryption_key.arn

  AllowTraffic = {
    CIDR = "10.0.0.0/16"
    IPSecGroupIds = []
    Self = true
  }
}

resource "aws_security_group" "example" {
  name = "example_pgsql_security_group"
  description = "Security group for PostgreSQL Database that allows traffic from the VPC"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
```

This configuration provisions a secure PostgreSQL database version 15 on AWS, within a specified VPC and uses various AWS services like RDS for the database instance, a subnet group for network configuration, and a security group to manage access. It also uses KMS for encryption, and defines custom parameters for the RDS instance via a parameter group. The `aws_db_subnet_group` specifies which subnets the database can associate with, increasing the reachability of the database within the VPC. The `allow_traffic` block defines the ingress and egress policies for the security group, allowing the database to listen on port 5432 and restricting egress traffic to only port 5432 traffic, thus mitigating any risk that the PostgreSQL instance might accidentally open a port that it shouldn't.

