  subnet_ids = [aws_subnet.main.id]
}

resource "aws_kms_key" "pg_key" {
  description             = "KMS key for PostgreSQL encryption"
  enable_key_rotation     = true
}

resource "aws_db_parameter_group" "pg_parameters" {
  name   = "my-parameter-group"
  family = "postgres11"

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

resource "aws_security_group" "db" {
  name        = "db-security-group"
  description = "Allow access to PostgreSQL"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_instance" "prod_postgres" {
  allocated_storage    = 20
  storage_type         = "gp2"
  storage_encrypted    = true
  engine               = "postgres"
  engine_version       = "11.6"
  instance_class       = "db.t3.micro"
  name                 = "mydatabase"
  username             = "dbadmin"
  password             = "verysecurepassword1234"
  parameter_group_name = aws_db_parameter_group.pg_parameters.name
  db_subnet_group_name = aws_db_subnet_group.main.id
  vpc_security_group_ids = [aws_security_group.db.id]
  multi_az              = true
  kms_key_id            = aws_kms_key.pg_key.arn
  backup_retention_period = 7
}
