  name     = "example"
  subnet_ids = [aws_subnet.example.id, aws_subnet.example.id]
}

resource "aws_kms_key" "database_key" {
  description = "KMS key for database encryption"
}

resource "aws_db_parameter_group" "example" {
  name        = "example"
  db_parameter = [
    {
      parameter_name = "rds.amazonaws.com"
      character_set_name = "example"
    },
  ]
  family = "postgres"
}

resource "aws_rds_instance" "example" {
  identifier        = "securedb-${random_id.suffix.hex}"
  allocated_storage = 100
  storage_type      = "gp2"
  engine            = "postgres"
  multi_az          = true
  storage_encrypted = true
  kms_key_id        = aws_kms_key.database_key.arn
  db_subnet_group_name = aws_db_subnet_group.example.id
  final_snapshot_identifier = "pgsnapshot"
  parameter_group_name    = aws_db_parameter_group.example.id
}
```

This configuration ensures that the PostgreSQL instance is secure and correctly set up within the specified AWS VPC. It includes secure storage, access management, and encryption specifications for a secure and high availability setup.

