  enable_case_insensitivity = true
  enabled_cloudwatch_logs_exports = ["error", "general"]
}

resource "aws_security_group" "example" {
  name        = "example-security-group"
  description = "Example security group for RDS MySQL Cluster"
  egress = [
    {
      description = "test"
      from_port   = 0
      to_port     = 0
      protocol    = "-1"
      cidr_blocks = ["0.0.0.0/0"]
    }
  ]
}

resource "aws_kms_key" "directory_encryption" {
  description = "A KMS key for directory encryption"
}

resource "aws_secretsmanager_secret" "rds_secret" {
  name = "example-rds-secret"
}

resource "aws_secretsmanager_secret_version" "rds_secret_v1" {
  secret_string_value = "mysql-password-here"
}
```

In this configuration:
- `aws_vpc` defines the VPC for the RDS cluster.
- `aws_db_subnet_group` is used to assign the subnets within the VPC to the RDS cluster.
- `aws_iam_role` grants necessary permissions for RDS to use AWS Secrets Manager.
- `aws_rds_cluster` defines the RDS Aurora MySQL cluster with secure credentials stored in Secrets Manager and an HTTP endpoint enabled for enhanced connection management.
- The `aws_security_group` defines the security rules that allow traffic to the RDS instance.
- `aws_kms_key` provides encryption capabilities for enhanced secrets management.
- `aws_secretsmanager_secret` and `aws_secretsmanager_secret_version` manage the secrets for the database credentials securely.

