resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault"
  acl    = "private"

  lifecycle {
    ignore_changes = [
      "abort_incomplete_multipart_upload", // Automatically converts stored objects to the GLACIER storage class
    ]
  }

  lifecycle_rule {
    rule_id                = "glacier_rule"
    enabled              = true
    expiration {
      days = 30
    }
    transition {
      days         = 0
      storage_class = "GLACIER"
    }
    transition {
      days         = 30
      storage_class = "GLACIER"
    }
  }
}

resource "aws_s3_bucket_notification" "glacier_notification" {
  bucket = aws_s3_bucket.glacier_vault.id
  lambda_function {
