    prevent_destroy = true
  }
}

resource "aws_s3_bucket_policy" "example_policy" {
  bucket = aws_s3_bucket.glacier_vault.id
  policy = file("${path.module}/s3_glacier_access_policy.json") // Reference to a local JSON policy file
}

resource "aws_s3_bucket_lifecycle_configuration" "example_lifecycle" {
  bucket = aws_s3_bucket.glacier_vault.id
  rule {
    id     = "glacier-storage-rule-${random_pet.pet.id}"
    filter {
      prefix = "archive/"
    }

    status = "Enabled"
    expiration {
      days = 365
    }
  }
}

resource "random_pet" "pet" {
  length = 4
}
```

### Explanation:

1. **S3 Bucket**: An AWS S3 bucket is created for storing the Glacier archive files. The bucket name includes a suffix to ensure uniqueness.
2. **Bucket Lifecycle**: A lifecycle rule is applied to transition objects to Glacier storage after a specified number of days.
3. **Bucket Policy**: A JSON policy is referenced to configure access permissions.
4. **Server-Side Encryption**: Configures default encryption for the vault.
5. **Random Pet**: A random seed generator is used to create the uniquely suffixed bucket name and policy rule ID. 

Please ensure the `s3_glacier_access_policy.json` file in your module path contains valid S3 bucket policy JSON to apply specific access controls. The `random_pet` resource generates a unique name suffix that aids in avoiding conflict with existing resources.

