response:
To generate a Terraform configuration for creating an AWS Application Load Balancer with an IP target group, the following HCL code can be used:

```hcl
resource "aws_lb" "example_alb" {
  name               = "my-alb"
  internal          = false
  load_balancer_type = "application"
  scheme            = "internet-facing"

  enable_deletion_protection = false
}

resource "aws_lb_target_group" "example_target_group" {
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.example.id

  health_check {
    interval            = 30
    healthy_threshold = 3
    unhealthy_threshold = 3
    timeout             = 5
    path               = "/health"
    protocol           = "HTTP"
    matcher            = "200-399"
  }
}

resource "aws_lb_listener" "example_listener" {
  load_balancer_arn = aws_lb.example_alb. 
  port              = 80
  protocol = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.example_target_group.arn
    forward {
      target_port = 80
      target_type = "instance"
    }
  }
}
```

This code defines an AWS Application Load Balancer and an associated IP target group using Terraform. The `aws_lb` resource is the Application Load Balancer itself, and `aws_lb_target_group` represents the target group with HTTP health checks. The `aws_lb_listener` resource configures the listener, and it uses the target group for routing traffic to the instances specified by their IP addresses within the defined VPC. Adjust the variables accordingly to fit into your setup.

extracted_code:
provider "aws" {
  region = "us-west-2"
}

resource "aws_lb" "example" {
  name               = "example-lb"
  load_balancer_type = "application"
  subnets            = ["subnet-0a1234567EXAMPLE", "subnet-0b1234567EXAMPLE"]

  enable_deletion_protection = false

  tags = {
    Name = "example-lb"
  }
}

resource "aws_lb_target_group" "lambda" {
  name     = "lambda-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = "vpc-12345678"

  target_type = "lambda"

  health_check {
    enabled             = true
    interval            = 30
    path                = "/"
    protocol            = "HTTP"
    matcher             = "200"
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_lambda_function" "example" {
  function_name = "example_lambda"

  filename         = "path/to/your/lambda/function.zip"
  source_code_hash = filebase64sha256("path/to/your/lambda/function.zip")
  handler          = "index.handler"
  role             = aws_iam_role.lambda_exec.arn
  runtime          = "nodejs12.x"
}

resource "aws_lambda_permission" "allow_alb" {
  statement_id  = "AllowExecutionFromLoadBalancer"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example.function_name
  principal     = "elasticloadbalancing.amazonaws.com"
  source_arn    = aws_lb_target_group.lambda.arn
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "lambda_exec_policy" {
  name = "lambda_exec_policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
        ]
        Effect = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      },
    ]
  })
}

