terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

locals {
  subnet_count = 2
}

resource "aws_vpc" "_" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "public" {
  count             = local.subnet_count
  vpc_id            = aws_vpc._.id
  cidr_block        = ["10.0.1.0/24",
                      "10.0.2.0/24",
                      "10.0.3.0/24",
                      "10.0.4.0/24"][count.index]
  availability_zone = data.aws_availability_zones.available.names[count.index]
}

resource "aws_internet_gateway" "_" {
  vpc_id = aws_vpc._.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc._.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway._.id
  }
}

resource "aws_route_table_association" "public" {
  count          = local.subnet_count
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

response:
To create a VPC in AWS with multiple public subnets and associate them with a route table configured for internet access via an Internet Gateway, you can use Terraform with the following configuration:

```hcl
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_internet_gateway" "example" {
  vpc_id = aws_vpc.example.id
}

resource "aws_route_table" "example" {
  vpc_id = aws_vpc.example.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.example.id
  }
}

resource "aws_subnet" "public" {
  count = 3 // Assuming multiple public subnets
  vpc_id            = aws_vpc.example.id
  cidr_block = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"] # Adjust CIDR blocks for each subnet

  availability_zone  = element(["us-west-2a", "us-west-2b", "us-west-2c"], count.index) // Assign availability zone based on count index
  route_table_id     = aws_route_table.example.id
}

resource "aws_route_table_association" "example" {
  count        = aws_subnet.public.count
  route_table_id   = aws_route_table.example.id
  subnet_id        = element(aws_subnet.public.*.id, count.index)
}
```

In this configuration:
- A VPC (`aws_vpc`) is created with a CIDR block.
- An Internet Gateway (`aws_internet_gateway`) is created and attached to the VPC.
- A route table (`aws_route_table`) is created with a route to the internet via the Internet Gateway.
- Multiple public subnets (`aws_subnet`) are created within the VPC, each with a different CIDR block for separation.
- Each subnet is associated with the route table for internet access via `aws_route_table_association`.

