To create a VPC in AWS with multiple public subnets and associate them with a route table configured for internet access via an internet gateway, you can use the following Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_internet_gateway" "example" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block            = "0.0.0.0/0"
    gateway_id        = aws_internet_gateway.example.id
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2a"
}

resource "aws_route_table_association" "public1_association" {
  subnet_id      = aws_subnet.public1.id
  route_table_id  = aws_route_table.public.id
}

resource "aws_subnet" "public2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone = "us-west-2b"
}

resource "aws_route_table_association" "public2_association" {
  subnet_id      = aws_subnet.public2.id
  route_table_id  = aws_route_table.public.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block            = "10.0.1.0/24"
    gateway_id        = aws_internet_gateway.example.id
  }
}
```

This configuration sets up an AWS VPC with a CIDR block of `10.0.0.0/16`, creates an internet gateway that connects the VPC, and multiple public subnets with route tables associated for internet access via the internet gateway. Adjust the CIDR blocks and availability zones according to your specific needs and ensure the resource IDs and nesting align logically with your account specifications.

