  default = "10.0.0.0/16"
}

variable "internet_gateway_name" {
  type    = string
  default = "example-igw"
}

variable "route_table_name" {
  type    = string
  default = "example-route-table"
}

resource "aws_vpc" "example" {
  cidr_block           = var.vpc_cidr_block
  enable_dns_support   = true
  enable_dns_hostnames  = true
  tags = {
    Name = var.vpc_name
  }
}

resource "aws_internet_gateway" "example" {
  vpc_id = aws_vpc.example.id

  tags = {
    Name = var.internet_gateway_name
  }
}

resource "aws_route_table" "example" {
  vpc_id = aws_vpc.example.id

  routes {
    cidr_block     = "0.0.0.0/0"
    gateway_id     = aws_internet_gateway.example.id
  }

  tags = {
    Name = var.route_table_name
  }
}
```

This configuration sets up an AWS VPC with DNS support and hostnames enabled, links an Internet Gateway to it, and configures a route table for outbound Internet access, tagging each resource with the respective variable names.

